spec.expr:
100 *
(
sum by(path)(
rate(product_intelligence_requests_total{
status_code!~"2..",
path=~"/api/v1/products.*"
}[5m])
)
/
sum by(path)(
rate(product_intelligence_requests_total{
path=~"/api/v1/products.*"
}[5m])
)
)

sort_desc(
(
sum by(path)(
rate(product_intelligence_request_duration_seconds_sum{
path=~"/api/v1/products.*"
}[5m])
)
/
sum by(path)(
rate(product_intelligence_request_duration_seconds_count{
path=~"/api/v1/products.*"
}[5m])
)
) * 1000
)
